/* Custom CSS - Add your custom styles here */

/* Submenu styles */
#menu .has-submenu {
    position: relative;
}

#menu .submenu {
    display: none;
    position: absolute;
    top: 100%;
    left: 0;
    background: var(--entry);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 8px 0;
    min-width: 150px;
    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
    z-index: 1000;
    margin-top: 4px;
    list-style: none;
}

#menu .has-submenu:hover .submenu {
    display: block;
}

#menu .submenu li {
    list-style: none;
    margin: 0;
    padding: 0;
}

#menu .submenu li a {
    display: block;
    padding: 8px 16px;
    color: var(--primary);
    text-decoration: none;
    white-space: nowrap;
    transition: background 0.2s ease;
}

#menu .submenu li a:hover {
    background: var(--theme);
}

#menu .submenu li a span.active {
    font-weight: 500;
    color: var(--secondary);
}

/* 添加下拉箭头指示器 */
#menu .has-submenu > a::after {
    content: " ▼";
    font-size: 0.7em;
    margin-left: 4px;
}
